scwin.gv_strExistTF = "";     	// 중복체크여부
scwin.gv_crryinEdiType = "";		//반입EDI구분
scwin.gv_crryoutEdiType = "";		//반출EDI구분
scwin.gv_odrNo			= "";
scwin.gv_wrkStDt		= "";
scwin.gv_wrkEndDt		= "";
scwin.gv_cntrNo			= "";
scwin.gv_dptWrkPlCd		= "";
scwin.gv_arvWrkPlCd		= "";
scwin.arrRtnVal = new Array();




scwin.onpageload = function() {

    var params = $c.data.getParameter();
    var arrParent = params.arrParent;
   // scwin.paramTitle = scwin.params["paramTitle"] == undefined ? "반출입예정정보EDI등록" : params.getParameter["paramTitle"];
//	scwin.gv_crryoutEdiType = scwin.params["crryoutEdiType"] == undefined ? DsConstants.CRRYINOUT_EDI_COPI_CODECO : request.getParameter["crryoutEdiType"];
 //   scwin.gv_crryinEdiType = scwin.params["crryinEdiType"] == undefined ? DsConstants.CRRYINOUT_EDI_COPI_CODECO : request.getParameter["crryinEdiType"];
    if(DsConstants.CRRYINOUT_EDI_COPI_CODECO == scwin.gv_crryoutEdiType){
         codeCoGroup.show();
        copinoGroup.hide();
    } else {
        //copinoGroup.show();
        codeCoGroup.hide();
    }
    if(params == undefined){

        ed_odrNo.setValue(arrParent[0][2] == null ? "" : arrParent[0][2]);
        ed_wrkStDt.setValue(arrParent[0][9] == null ? "" : arrParent[0][9]); 
        ed_wrkEndDt.setValue(arrParent[0][10] == null ? "" : arrParent[0][10]);
        ed_cntrNo.setValue(arrParent[0][11] == null ? "" : arrParent[0][11]);
        ed_dptWrkPlCd.setValue(arrParent[0][12] == null ? "" : arrParent[0][12]);
        ed_arvWrkPlCd.setValue(arrParent[0][13] == null ? "" : arrParent[0][13]);
        ed_dptWrkPlNm.setValue(arrParent[0][14] == null ? "" : arrParent[0][14]);
        ed_arvWrkPlNm.setValue(arrParent[0][15] == null ? "" : arrParent[0][15]);
        gv_crryoutEdiType		= arrParent[0][16] == null ? "" : arrParent[0][16];
        gv_crryinEdiType		= arrParent[0][17] == null ? "" : arrParent[0][17];
    } else {
        $c.gus.cfAlertMsg("EDI정보를 가져오지 못했습니다");
        return;
    }
    $c.gus.cfInitObjects(tb_srchCond);

};

scwin.f_Retrieve = function(gubun){
    var params = $c.data.getParameter();
    var arrParent = params.arrParent;

    if (gubun == null || gubun == "" || gubun == 0) {
        ds_resultsCopino1.removeAll();
        ds_resultsCopino2.removeAll();
        btnFlag = "";  // 신규, 수정 구분자
        rowFlag = "";  // 등록, 수정 후 저장 안하고 다른 master row 선택 불가능 구분자

        ds_search.set("qryClsCd", arrParent[0][0] == null ? "" : arrParent[0][0] );
        ds_search.set( "transWrkIndictNo", arrParent[0][1] == null ? "" : arrParent[0][1]);
        ds_search.set( "odrNo", arrParent[0][2] == null ? "" :arrParent[0][2]);
        ds_search.set( "cntrSeq", arrParent[0][3] == null ? "" :arrParent[0][3]); 
        ds_search.set( "wrkPathSeq", arrParent[0][4] == null ? "" : arrParent[0][4]); 
        ds_search.set( "wrkStpSeq", arrParent[0][5] == null ? "" : arrParent[0][5]);
        ds_search.set( "crryoutDt", ed_wrkStDt.getValue());
        ds_search.set( "crryinDt", ed_wrkEndDt.getValue());
        ds_search.set( "cntrNo", ed_cntrNo.getValue());
        ds_search.set( "dptWrkPlCd", ed_dptWrkPlCd.getValue());
        ds_search.set( "arvWrkPlCd", ed_arvWrkPlCd.getValue());
        ds_search.set( "crryoutEdiType", scwin.gv_crryoutEdiType);
        ds_search.set( "crryinEdiType", scwin.gv_crryinEdiType);

        ds_search.set( "vehclNo", arrParent[0][7] == null ? "" : arrParent[0][7]);
        ds_search.set( "vehclIdCardNo", arrParent[0][8] == null ? "" : arrParent[0][8]);

        //반출입에서 호출하는경우
        if (arrParent[0][0] == "1") {
            if (arrParent[1] != null && arrParent[1].length > 0) {
                ds_search.set("transWrkIndictNo", arrParent[1][0] == null ? "" : arrParent[1][0]) ;
                ds_search.set("vehclNo", arrParent[1][1] == null ? "" : arrParent[1][1]) ;
                ds_search.set("vehclIdCardNo", arrParent[1][2] == null ? "" : arrParent[1][2]) ;
                ds_search.set("drvNm", arrParent[1][3] == null ? "" : arrParent[1][3]) ;
                ds_search.set("cntctPl", arrParent[1][4] == null ? "" : arrParent[1][4]) ;
                ds_search.set("crryoutDt", arrParent[1][5] == null ? "" :arrParent[1][5]) ;
                ds_search.set("crryoutHh", arrParent[1][6] == null ? "" : arrParent[1][6]) ;
                ds_search.set("crryinDt", arrParent[1][7] == null ? "" : arrParent[1][7]) ;
                ds_search.set("crryinHh", arrParent[1][8] == null ? "" : arrParent[1][8]) ;
                ds_search.set("vehclShortCd", arrParent[1][9] == null ? "" :arrParent[1][9]) ;
                ds_search.set("eqCd", arrParent[1][10] == null ? "" : arrParent[1][10]) ;
            }
        }
         $c.sbm.execute(sbm_retrieve);
    }
};

