scwin.f_disableCompCopiCodeco = function(gubun, inout) {

    if(gubun == "HY") {		//현대용당일경우

        //직상차여부, 철송주체, 철송요청일자, 철송요청시간, 진수화인, 착지, 화물관리번호
        if(inout == 1) {
             $c.gus.cfDisableObjects([acb_drtOnYn3, acb_railroadCore3, ica_railroadReqDt3, acb_railroadReqHh3, ed_consignee3, acb_arvRailroadPlc3, ed_blNo31]);
        } else {
             $c.gus.cfDisableObjects([acb_drtOnYn4, acb_railroadCore4, ica_railroadReqDt4, acb_railroadReqHh4, ed_consignee4, acb_arvRailroadPlc4, ed_blNo41]);
        }

    } else if(gubun == "DT") {	//대한통운일경우

        //화주코드, 화주명, From DEPOT, From 지역,TO DEPOT, TO 지역, REMARK, 직상차여부, PTI여부,
        //철송주체, 철송요청일자, 철송요청시간, 진수화인, 착지, TS구분, 수출면장번호,
        //면장기일, BL번호
        if(inout == 1) {
             $c.gus.cfDisableObjects([btn_mchtCd3, ed_mchtCd3, ed_mchtNm3, ed_dptDepot3, ed_dptRgn3, ed_arvDepot3, ed_arvRgn3, ed_unqItm3, acb_drtOnYn3, acb_transCls3,
                                acb_railroadCore3, ica_railroadReqDt3, ica_railroadReqDt, acb_railroadReqHh3, ed_consignee3, acb_arvRailroadPlc3, acb_tsCls3, ed_expLicenseNo3,
                                 ica_licenseFdd3, ed_blNo3]);
        } else {
             $c.gus.cfDisableObjects([btn_mchtCd4, ed_mchtCd4, ed_mchtNm4, ed_dptDepot4, ed_dptRgn4, ed_arvDepot4, ed_arvRgn4, ed_unqItm4, acb_drtOnYn4, acb_transCls4,
                                acb_railroadCore4, ica_railroadReqDt4, ica_railroadReqDt4, acb_railroadReqHh4, ed_consignee4, acb_arvRailroadPlc4, acb_tsCls4, ed_expLicenseNo4,
                                 ica_licenseFdd4, ed_blNo4]);
        }

    } else {		//현대경인일경우

        //직상차여부, TS구분, 수출면장번호, 화물관리번호
        if(inout == 1) {
             $c.gus.cfDisableObjects([acb_drtOnYn3, acb_tsCls3, ed_expLicenseNo3, ed_blNo31]);
        } else {
            $c.gus.cfDisableObjects([acb_drtOnYn4, acb_tsCls4, ed_expLicenseNo4, ed_blNo41]);
        }

    }

}

