scwin.sbm_retrieveDoneAfter = function(){
    if(ds_resultsCopino.getRowCount() == 0 ){
    //cfAlertMsg(MSG_CM_WRN_002);
        return;
  	}

	//현재의 조회조건을 저장을 위해 복사해둔다
	//cfCopyDataSet(ds_search, ds_hiddenSearch);

	// 차량정보를 위해 헤더만 복사
	ds_resultsCopino1.removeAll()();
	ds_resultsCopino2.removeAll();

	//var v_features = "";
	//v_features = "copyHeader=yes,rowFrom=0,rowCnt=0";
	//cfCopyDataSet(ds_resultsCopino, ds_resultsCopino1, v_features);
	//cfCopyDataSet(ds_resultsCopino, ds_resultsCopino2, v_features);

	var v_bIsCrryOut = false;
	var v_bIsCrryIn  = false;

