			} else if( ds_resultsCopiCodeco2.setCellData(0, "sndClsCd") ==  DsConstants.EDI_SND_CLS_CD_SND_WAIT ) {
				txt_sndClsCd4.setValue("전송대기");
			} else {
				txt_sndClsCd4.setValue("미등록");
			}

		}
	}

	if (v_bIsCrryOut) {
		cfEnableObjects([tb_crryOutCopiCodeco, cbx_crryOutCopiCodeco]);
		scwin.f_disableCompCopiCodeco(ds_resultsCopiCodeco1.setCellData(0, "cls"), 1);
		cbx_crryOutCopiCodeco.setSelectedIndex(1)// = true;
		txt_reason3.setReadOnly(true);// = true;
	} else {
		//$c.gus.cfDisableObjects([tb_crryOutCopiCodeco, cbx_crryOutCopiCodeco]);
        $c.gus.cfDisableObjects([ cbx_crryOutCopiCodeco]);
		cbx_crryOutCopiCodeco.setSelectedIndex(0);// = false;
	}

	if (v_bIsCrryIn) {
		// $c.gus.cfEnableObjects([tb_crryInCopiCodeco, cbx_crryInCopiCodeco]);
         $c.gus.cfDisableObjects([ cbx_crryInCopiCodeco]);
		scwin.f_disableCompCopiCodeco(ds_resultsCopiCodeco2.setCellData(0, "cls"), 2);
		cbx_crryInCopiCodeco.setSelectedIndex(1);// = true;
		txt_reason4.setReadOnly(true) //= true;
	} else {
		 //$c.gus.cfDisableObjects([tb_crryInCopiCodeco, cbx_crryInCopiCodeco]);
         $c.gus.cfDisableObjects([ cbx_crryInCopiCodeco]);
		cbx_crryInCopiCodeco.setSelectedIndex(0) //= false;
	}

};


