scwin.ed_vehclNoFull1_onblur = function (e) {

    if ( !$c.gus.cfValidate([ed_vehclNoFull1]) ) {
		ed_vehclNoFull1.setValue("");
	}
	//[사전정보그룹구분코드=경인ICD and 작업단계코드<>철송]
	if ( ds_resultsCopino1.setCellData(0, "preInfoGrpClsCd") == DsConstants.EDI_GRPCD_KYUNGIN_ICD
			&& ds_resultsCopino1.setCellData(0, "wrkStpCd") != DsConstants.WRK_STP_CD_RAILROAD 
			&& ds_resultsCopino1.setCellData(0, "wrkStpCd") != ed_vehclNoFull1.getValue() ) {

		$c.gus.cfEnableObjects([ed_vehclNoFrtcarNo1]);
	}
};

