scwin.ed_frzTemper2_onblur = function (e) {
    	if (!$c.gus.cfValidate([ed_frzTemper2]) ) {
		txt_frzTemper2.setValue("");
	} else {
		if (ds_resultsCopino2.getCellData(0, "temperCls") != "") {
			if ( ed_frzTemper2.getValue() == null || ed_frzTemper2.getValue() == "" ) {
				txt_frzTemper2.setValue(DsConstants.EDI_TEMPER_CLS_DRY) ;
			} else {
				txt_frzTemper2.setValue(DsConstants.EDI_TEMPER_CLS_CEL);
			}
		} else {
			txt_frzTemper2.setValue("");
		}
	}
};



